class SummaryRanges:

    def __init__(self):
        self.intervals = []

    def addNum(self, value: int) -> None:
        if not self.intervals:
            self.intervals.append([value, value])
            return

        i = 0
        while i < len(self.intervals):
            if value >= self.intervals[i][0] and value <= self.intervals[i][1]:
                if value == self.intervals[i][0]:
                    self.intervals[i][1] = max(self.intervals[i][1], value)
                else:
                    self.intervals[i][0] = min(self.intervals[i][0], value)
                return
            i += 1

        self.intervals.append([value, value])

    def getIntervals(self) -> List[List[int]]:
        return self.intervals
